def check_stock(stock_id):
    ticker = f"{stock_id}.TW"
    try:
        # 下載至少一年的資料以確保能計算 240 日均線
        df = yf.download(ticker, period="1y", interval="1d", progress=False)
        if df.empty or len(df) < 240:
            return None
        
        # 由於 yfinance 回傳的多層級 MultiIndex columns，需要展平或取單一個股
        if isinstance(df.columns, pd.MultiIndex):
            df = df.xs(ticker, level=1, axis=1)

        # 確保價格資料為浮點數
        df['Close'] = df['Close'].astype(float)
        df['Open'] = df['Open'].astype(float)
        df['Volume'] = df['Volume'].astype(float)
        
        # 1. 計算 KD (9, 3, 3)
        stoch = df.ta.stoch(k=9, d=3)
        if stoch is None or len(stoch) < 2: return None
        k_col = stoch.columns[0]
        d_col = stoch.columns[1]
        
        # 2. 計算均線 (需5、10、20)
        mas = [5, 10, 20]
        for ma in mas:
            df[f'SMA_{ma}'] = ta.sma(df['Close'], length=ma)
            
        # 3. 計算成交量均線 (VMA 5)
        df['VMA_5'] = ta.sma(df['Volume'], length=5)
            
        # 檢查過去 5 天內是否發生此條件
        if len(df) < 6: return None
        recent_indices = df.index[-6:]
        
        for i in range(1, 6):
            prev_idx = recent_indices[i-1]
            last_idx = recent_indices[i]
            
            close_price = df['Close'].loc[last_idx]
            open_price = df['Open'].loc[last_idx]
            vol = df['Volume'].loc[last_idx]
            prev_vol = df['Volume'].loc[prev_idx]
            vma5 = df['VMA_5'].loc[last_idx]
            
            # 條件 1: K線長紅 (收盤大於開盤，實體長度>3%)
            cond_long_red = (close_price > open_price) and open_price > 0 and ((close_price - open_price) / open_price >= 0.03)
            
            # 條件 2: 均線糾結後站上5MA/10MA/20MA均線
            # 計算當日與前一日的均線值
            ma_values = [df[f'SMA_{ma}'].loc[last_idx] for ma in mas]
            prev_ma_values = [df[f'SMA_{ma}'].loc[prev_idx] for ma in mas]
            
            # 前一日均線糾結 (最高均線與最低均線的差距小於3%)
            ma_entangled = max(prev_ma_values) / min(prev_ma_values) < 1.03 if min(prev_ma_values) > 0 else False
            # 今日站上所有均線
            stand_on_mas = all(close_price > ma for ma in ma_values)
            
            cond_ma = ma_entangled and stand_on_mas
            
            # 條件 3: KD 黃金交叉 (前一日 K <= D，今日 K > D)
            cond_kd = stoch[k_col].loc[prev_idx] <= stoch[d_col].loc[prev_idx] and stoch[k_col].loc[last_idx] > stoch[d_col].loc[last_idx]
            
            # 條件 4: 成交量上揚 (今日成交量 > 昨日成交量 且 今日成交量 > 5日均量)
            cond_vol_up = (vol > prev_vol) and (vol > vma5)
            
            if cond_long_red and cond_ma and cond_kd and cond_vol_up:
                return {
                    "代號": stock_id,
                    "名稱": STOCK_NAMES.get(stock_id, ""),
                    "觸發日期": str(last_idx.date()),
                    "收盤價": round(close_price, 2),
                    "型態": "帶量長紅",
                    "均線": "糾結後站上",
                    "KD": "黃金交叉",
                    "成交量": "上揚"
                }
    except Exception as e:
        # 忽略下載或計算失敗的個股
        pass
    return None

def main():
    print("開始篩選符合條件的台股...")
    print("條件：1. 帶量長紅 2. 均線糾結後站上5/10/20均線 3. KD黃金交叉 4. 成交量上揚 (回推過去5天)\n")
    
    results = []
    # 使用多執行緒加速下載與計算
    with ThreadPoolExecutor(max_workers=10) as executor:
        for res in executor.map(check_stock, TW_STOCKS):
            if res:
                results.append(res)
                
    if not results:
        print("目前沒有符合這些特定條件的篩選結果。")
    else:
        print("🎉 篩選出以下強勢個股：")
        df_results = pd.DataFrame(results)
        print(df_results.to_markdown(index=False))

if __name__ == "__main__":
    main()
